// @kern-source: tool-observability:217
function readJsonlRecords(filePath: string): Array<Record<string,unknown>> {
  if (!existsSync(filePath)) {
    return [];
  }
  const out: Array<Record<string, unknown>> = [];
  const text = readFileSync(filePath, 'utf-8');
  for (const line of text.split('\n')) {
    const trimmed = line.trim();
    if (!trimmed) {
      continue;
    }
    try {
      const parsed = JSON.parse(trimmed);
      if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
        out.push(parsed as Record<string, unknown>);
      }
    } catch (e) {
      out.push({ kind: 'parse_error', raw: trimmed.slice(0, 240) });
    }
  }
  return out;
}

// @kern-source: tool-observability:235
function eventTimeMs(record: Record<string,unknown>): number {
  const ts = (typeof record.ts === 'string') ? hostDateMs(record.ts) : NaN;
  return Number.isFinite(ts) ? ts : 0;
}

/**
 * Replay the compact Cesar approval ledger and tool timeline into a readable per-turn summary. This is the CLI/UI surface for post-mortem harness debugging.
 */
// @kern-source: tool-observability:240
export function replayCesarHarnessLogs(opts?: {runsDir?:string,turnId?:string,limit?:number}): CesarHarnessReplayResult {
  const dir = opts?.runsDir ?? RUNS_DIR;
  const limitRaw = Number(opts?.limit ?? 5);
  const limit = Number.isFinite(limitRaw) && limitRaw > 0 ? Math.floor(limitRaw) : 5;
  const timeline = readJsonlRecords(join(dir, 'cesar-tool-timeline.jsonl'));
  const approvals = readJsonlRecords(join(dir, 'cesar-approval-ledger.jsonl'));
  const errors = timeline.filter((r) => r.kind === 'parse_error').length + approvals.filter((r) => r.kind === 'parse_error').length;

  const grouped = new Map<string, Array<Record<string, unknown>>>();
  for (const rec of timeline) {
    const turnId = typeof rec.turnId === 'string' ? rec.turnId : 'unknown';
    if (opts?.turnId && turnId !== opts.turnId) continue;
    const arr = grouped.get(turnId) ?? [];
    arr.push(rec);
    grouped.set(turnId, arr);
  }

  const approvalByTurn = new Map<string, Array<Record<string, unknown>>>();
  for (const rec of approvals) {
    const turnId = typeof rec.turnId === 'string' ? rec.turnId : 'unknown';
    if (opts?.turnId && turnId !== opts.turnId) continue;
    const arr = approvalByTurn.get(turnId) ?? [];
    arr.push(rec);
    approvalByTurn.set(turnId, arr);
  }

  const turnSummaries = [...grouped.entries()].map(([turnId, events]) => {
    events.sort((a, b) => eventTimeMs(a) - eventTimeMs(b));
    const start = events.find((e) => e.event === 'turn_start') ?? events[0] ?? {};
    const summary = events.find((e) => e.event === 'turn_summary')?.summary as Record<string, unknown> | undefined;
    const toolEvents = events.filter((e) => e.event === 'tool_call' || e.event === 'tool_result');
    const interruptCount = events.filter((e) => e.event === 'xml_interrupt').length;
    const approvalsForTurn = approvalByTurn.get(turnId) ?? [];
    const lastEvent = events[events.length - 1] ?? start;
    return {
      turnId,
      ts: start.ts ?? lastEvent.ts,
      engineId: start.engineId ?? summary?.engineId,
      cwd: start.cwd,
      durationMs: summary?.durationMs,
      eventCount: events.length,
      toolEventCount: toolEvents.length,
      toolCallCount: toolEvents.filter((e) => e.event === 'tool_call').length,
      toolResultCount: toolEvents.filter((e) => e.event === 'tool_result').length,
      approvalCount: approvalsForTurn.length,
      xmlInterrupts: interruptCount,
      tools: [...new Set(toolEvents.map((e) => String(e.tool ?? '')).filter(Boolean))],
      approvals: approvalsForTurn.map((a) => ({
        tool: a.tool,
        decision: a.decision,
        source: a.source,
        reason: a.reason,
        path: a.path,
      })),
    } as Record<string, unknown>;
  });

  turnSummaries.sort((a, b) => eventTimeMs(b) - eventTimeMs(a));
  const selected = turnSummaries.slice(0, limit);

  const lines: string[] = [];
  lines.push(`Cesar harness replay: ${selected.length}/${turnSummaries.length} turn(s), ${timeline.length} timeline event(s), ${approvals.length} approval decision(s)`);
  if (errors > 0) lines.push(`Parse errors: ${errors}`);
  if (selected.length === 0) {
    lines.push(opts?.turnId ? `No events found for turnId ${opts.turnId}.` : 'No Cesar harness timeline records found yet.');
  }
  for (const turn of selected) {
    const duration = typeof turn.durationMs === 'number' ? `${Math.round(turn.durationMs)}ms` : 'duration unknown';
    const tools = Array.isArray(turn.tools) && turn.tools.length > 0 ? (turn.tools as string[]).join(', ') : 'no tools';
    lines.push('');
    lines.push(`Turn ${turn.turnId}`);
    lines.push(`  engine=${turn.engineId ?? 'unknown'} ${duration} events=${turn.eventCount} tools=${turn.toolEventCount} approvals=${turn.approvalCount} xmlInterrupts=${turn.xmlInterrupts}`);
    lines.push(`  tools: ${tools}`);
    const turnApprovals = Array.isArray(turn.approvals) ? turn.approvals as Array<Record<string, unknown>> : [];
    for (const approval of turnApprovals.slice(0, 5)) {
      lines.push(`  approval: ${approval.tool ?? 'tool'} ${approval.decision ?? 'unknown'} via ${approval.source ?? 'unknown'}${approval.reason ? ` - ${approval.reason}` : ''}`);
    }
    if (turnApprovals.length > 5) lines.push(`  approval: ... ${turnApprovals.length - 5} more`);
  }

  return {
    turnCount: selected.length,
    eventCount: timeline.length,
    approvalCount: approvals.length,
    errorCount: errors,
    rendered: lines.join('\n'),
    turns: selected,
  };
}
